  1→import { useMemo } from 'react';
  2→import { format, startOfWeek, endOfWeek, subWeeks } from 'date-fns';
  3→import { useInsights } from '@/hooks/useInsights';
  4→import { useLlmConfig } from '@/hooks/useConfig';
  5→import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
  6→import { Badge } from '@/components/ui/badge';
  7→import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
