 35→export default function JournalPage() {
 36→  const { data: insights = [], isLoading, isError, refetch } = useInsights();
 37→  const { data: llmConfig } = useLlmConfig();
 38→
 39→  const llmConfigured = !!(llmConfig?.provider && llmConfig?.model);
 40→
 41→  // Group learnings and decisions by week for the timeline
 42→  const insightsByWeek = useMemo(() => {
 43→    const relevant = insights.filter(
 44→      (i) => i.type === 'learning' || i.type === 'decision' || i.type === 'technique'
 45→    );
 46→    const grouped: Record<string, Insight[]> = {};
 47→    relevant.forEach((insight) => {
 48→      const weekKey = getWeekKey(insight.timestamp);
 49→      if (!grouped[weekKey]) grouped[weekKey] = [];
 50→      grouped[weekKey].push(insight);
 51→    });
 52→    return grouped;
 53→  }, [insights]);
 54→
 55→  const sortedWeeks = useMemo(
 56→    () => Object.keys(insightsByWeek).sort((a, b) => b.localeCompare(a)),
 57→    [insightsByWeek]
 58→  );
 59→
 60→  return (
 61→    <div className="p-6 space-y-6">
 62→      <div>
 63→        <h1 className="text-2xl font-bold">Knowledge Journal</h1>
 64→        <p className="text-muted-foreground">
 65→          A chronological timeline of your learnings and decisions
 66→        </p>
 67→      </div>
 68→
 69→      {isError && (
 70→        <ErrorCard message="Failed to load journal data" onRetry={refetch} />
 71→      )}
 72→
 73→      <Tabs defaultValue="timeline">
 74→        <TabsList>
 75→          <TabsTrigger value="timeline" className="gap-2">
 76→            <Clock className="h-4 w-4" />
 77→            Timeline
 78→          </TabsTrigger>
 79→          <TabsTrigger value="patterns" className="gap-2">
 80→            <GitBranch className="h-4 w-4" />
 81→            Patterns
 82→          </TabsTrigger>
 83→        </TabsList>
 84→
 85→        {/* Timeline tab */}
 86→        <TabsContent value="timeline" className="space-y-2 mt-4">
 87→          {isLoading ? (
 88→            <div className="text-center py-12 text-muted-foreground">Loading journal...</div>
 89→          ) : sortedWeeks.length === 0 ? (
 90→            <div className="text-center py-12 text-muted-foreground">
 91→              No learnings or decisions recorded yet. They appear here as you analyze sessions.
 92→            </div>
 93→          ) : (
 94→            <div className="space-y-8">
 95→              {sortedWeeks.map((weekKey) => {
 96→                const weekInsights = insightsByWeek[weekKey];
 97→                const weekLearnings = weekInsights.filter(
 98→                  (i) => i.type === 'learning' || i.type === 'technique'
 99→                );
100→                const weekDecisions = weekInsights.filter((i) => i.type === 'decision');
101→
102→                return (
103→                  <div key={weekKey} className="space-y-3">
104→                    {/* Week header */}
105→                    <div className="flex items-center gap-3">
106→                      <h2 className="text-sm font-semibold text-foreground">
107→                        {getWeekLabel(weekKey)}
108→                      </h2>
109→                      <div className="flex gap-2">
110→                        {weekLearnings.length > 0 && (
111→                          <Badge variant="secondary" className="text-xs gap-1">
112→                            <Lightbulb className="h-3 w-3" />
113→                            {weekLearnings.length} learning
114→                            {weekLearnings.length !== 1 ? 's' : ''}
115→                          </Badge>
116→                        )}
117→                        {weekDecisions.length > 0 && (
118→                          <Badge variant="secondary" className="text-xs gap-1">
119→                            <Target className="h-3 w-3" />
120→                            {weekDecisions.length} decision
121→                            {weekDecisions.length !== 1 ? 's' : ''}
122→                          </Badge>
123→                        )}
124→                      </div>
125→                      <div className="flex-1 h-px bg-border" />
126→                    </div>
127→
128→                    {/* Insights in this week, sorted newest first */}
129→                    <div className="space-y-2 pl-2 border-l-2 border-border ml-2">
130→                      {[...weekInsights]
131→                        .sort(
132→                          (a, b) =>
133→                            new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
134→                        )
135→                        .map((insight) => {
136→                          const isLearning =
137→                            insight.type === 'learning' || insight.type === 'technique';
138→                          return (
139→                            <div key={insight.id} className="relative pl-4 py-2 group">
140→                              {/* Timeline dot */}
141→                              <div
142→                                className={`absolute left-[-9px] top-[14px] h-3 w-3 rounded-full border-2 border-background ${
143→                                  isLearning ? 'bg-yellow-500' : 'bg-blue-500'
144→                                }`}
145→                              />
146→                              <div className="flex items-start gap-2">
147→                                {isLearning ? (
148→                                  <Lightbulb className="h-3.5 w-3.5 text-yellow-500 mt-0.5 shrink-0" />
149→                                ) : (
150→                                  <Target className="h-3.5 w-3.5 text-blue-500 mt-0.5 shrink-0" />
151→                                )}
152→                                <div className="min-w-0 flex-1">
153→                                  <p className="text-sm font-medium leading-snug">
154→                                    {insight.title}
155→                                  </p>
156→                                  {insight.content && (
157→                                    <p className="text-xs text-muted-foreground mt-0.5 line-clamp-2">
158→                                      {insight.content}
159→                                    </p>
160→                                  )}
161→                                  <p className="text-xs text-muted-foreground mt-1">
162→                                    {insight.project_name} &middot;{' '}
163→                                    {format(new Date(insight.timestamp), 'MMM d')}
164→                                  </p>
165→                                </div>
166→                                <Badge
167→                                  variant="outline"
168→                                  className={`text-xs shrink-0 ${
169→                                    isLearning
170→                                      ? 'text-yellow-700 border-yellow-300 dark:text-yellow-400 dark:border-yellow-700'
171→                                      : 'text-blue-700 border-blue-300 dark:text-blue-400 dark:border-blue-700'
172→                                  }`}
173→                                >
174→                                  {insight.type === 'technique' ? 'technique' : insight.type}
175→                                </Badge>
176→                              </div>
177→                            </div>
178→                          );
179→                        })}
180→                    </div>
181→                  </div>
182→                );
183→              })}
184→            </div>
185→          )}
186→        </TabsContent>
187→
188→        {/* Patterns tab */}
189→        <TabsContent value="patterns" className="space-y-6 mt-4">
190→          <Card>
191→            <CardHeader>
192→              <div className="flex items-center justify-between">
193→                <div>
194→                  <CardTitle className="flex items-center gap-2 text-base">
195→                    <Sparkles className="h-4 w-4 text-purple-500" />
196→                    AI Pattern Analysis
197→                  </CardTitle>
198→                  <CardDescription>
199→                    Discover recurring patterns in your work using your configured AI provider
200→                  </CardDescription>
201→                </div>
202→              </div>
203→            </CardHeader>
204→            <CardContent>
205→              {!llmConfigured ? (
206→                <div className="text-center py-8 text-muted-foreground">
207→                  <p>Configure an AI provider in Settings to use this feature.</p>
208→                  <Link
209→                    to="/settings"
210→                    className="text-primary text-sm underline hover:text-primary/80 mt-2 inline-block"
211→                  >
212→                    Go to Settings
213→                  </Link>
214→                </div>
215→              ) : insights.length === 0 ? (
216→                <div className="text-center py-8 text-muted-foreground">
217→                  Analyze some sessions first to see patterns here.
218→                </div>
219→              ) : (
220→                <div className="text-center py-8 text-muted-foreground space-y-3">
221→                  <p>
222→                    You have {insights.length} insight{insights.length !== 1 ? 's' : ''} across{' '}
223→                    {sortedWeeks.length} week{sortedWeeks.length !== 1 ? 's' : ''}.
224→                  </p>
225→                  <p className="text-sm">
226→                    Pattern analysis uses the session analysis feature. Go to a session and click
227→                    "Analyze" to generate insights, then check back here for timeline trends.
228→                  </p>
229→                  <Link
230→                    to="/sessions"
231→                    className="text-primary text-sm underline hover:text-primary/80 inline-block"
232→                  >
233→                    View Sessions
234→                  </Link>
235→                </div>
236→              )}
237→            </CardContent>
238→          </Card>
239→        </TabsContent>
240→      </Tabs>
241→    </div>
242→  );
243→}
