  1→#!/usr/bin/env node
  2→
  3→import { readFileSync } from 'fs';
  4→import { Command } from 'commander';
  5→import { initCommand } from './commands/init.js';
  6→import { syncCommand, getTrivialSessions, pruneTrivialSessions } from './commands/sync.js';
  7→import { statusCommand } from './commands/status.js';
  8→import { installHookCommand, uninstallHookCommand } from './commands/install-hook.js';
  9→import { openCommand } from './commands/open.js';
 10→import { dashboardCommand } from './commands/dashboard.js';
 11→import { resetCommand } from './commands/reset.js';
 12→import { statsCommand } from './commands/stats/index.js';
 13→import { configCommand } from './commands/config.js';
 14→import { telemetryCommand } from './commands/telemetry.js';
 15→import { reflectCommand } from './commands/reflect.js';
 16→import { showTelemetryNoticeIfNeeded } from './utils/telemetry.js';
 17→
 18→const pkg = JSON.parse(readFileSync(new URL('../package.json', import.meta.url), 'utf-8'));
 19→
 20→const program = new Command();
 21→
 22→program
 23→  .name('code-insights')
 24→  .description('AI coding session analytics — sync, stats, and insights')
 25→  .version(pkg.version);
 26→
 27→program
 28→  .command('init')
 29→  .description('Set up Code Insights (initializes local database)')
 30→  .action(initCommand);
 31→
 32→const syncCmd = program
 33→  .command('sync')
 34→  .description('Sync AI coding sessions to local SQLite database')
 35→  .option('-f, --force', 'Force re-sync all sessions (also restores hidden sessions)')
 36→  .option('-p, --project <name>', 'Only sync sessions from a specific project')
 37→  .option('-s, --source <name>', 'Only sync sessions from a specific tool (e.g., claude-code, cursor)')
 38→  .option('--dry-run', 'Show what would be synced without making changes')
 39→  .option('-q, --quiet', 'Suppress output (useful for hooks)')
 40→  .option('-v, --verbose', 'Show diagnostic warnings from providers')
 41→  .option('--regenerate-titles', 'Regenerate titles for all sessions')
 42→  .action(syncCommand);
 43→
 44→syncCmd
 45→  .command('prune')
 46→  .description('Soft-delete sessions with ≤2 messages (trivial abandoned sessions)')
 47→  .action(async () => {
 48→    const chalk = (await import('chalk')).default;
 49→    const { default: inquirer } = await import('inquirer');
 50→    console.log(chalk.cyan('\n  Code Insights — Prune\n'));
 51→
 52→    const sessions = getTrivialSessions();
 53→    if (sessions.length === 0) {
 54→      console.log(chalk.green('  No trivial sessions found. Nothing to prune.'));
 55→      return;
 56→    }
 57→
 58→    console.log(chalk.white(`  Found ${sessions.length} session${sessions.length !== 1 ? 's' : ''} with ≤2 messages:\n`));
 59→    for (const s of sessions) {
 60→      const label = s.title ?? chalk.dim('(no title)');
 61→      console.log(`  ${chalk.dim('·')} ${label} ${chalk.dim(`[${s.project_name}, ${s.message_count} msg]`)}`);
 62→    }
 63→    console.log('');
 64→
 65→    const { confirmed } = await inquirer.prompt<{ confirmed: boolean }>([
 66→      {
 67→        type: 'confirm',
 68→        name: 'confirmed',
 69→        message: `Soft-delete these ${sessions.length} session${sessions.length !== 1 ? 's' : ''}? (Restorable with sync --force)`,
 70→        default: false,
 71→      },
 72→    ]);
 73→
 74→    if (!confirmed) {
 75→      console.log(chalk.yellow('\n  Cancelled. No sessions were hidden.'));
 76→      return;
 77→    }
 78→
 79→    const { deleted } = pruneTrivialSessions(sessions.map((s) => s.id));
 80→    console.log(chalk.green(`\n  Hidden ${deleted} session${deleted !== 1 ? 's' : ''}.`));
 81→    console.log(chalk.dim('  Use code-insights sync --force to restore hidden sessions.'));
 82→  });
 83→
 84→program
 85→  .command('status')
 86→  .description('Show Code Insights status and statistics')
 87→  .action(statusCommand);
 88→
 89→program
 90→  .command('install-hook')
 91→  .description('Install Claude Code hook for automatic sync')
 92→  .action(installHookCommand);
 93→
 94→program
 95→  .command('uninstall-hook')
 96→  .description('Remove Claude Code hook')
 97→  .action(uninstallHookCommand);
 98→
 99→program
100→  .command('open')

 1→// Utilities for the shareable AI Fluency Score card.
 2→// Canvas 2D implementation — no external dependencies, pixel-perfect text rendering.
 3→// V3: Score card + fingerprint — single hero score, 5 rainbow bars, evidence lines.
 4→//
 5→// Resolution: drawn at 2× physical pixels (2400×1260) for HiDPI sharpness,
 6→// exported as 1200×630 PNG (OG image standard). The 2× internal resolution
 7→// ensures crisp text rendering on Retina/HiDPI displays.
 8→
 9→import type { PQDimensionScores } from '@/lib/api';
10→import {
11→  drawIcon, drawToolIcon, loadToolIcons, deduplicateToolsForIcons,
12→  ICON_BOOK_OPEN, ICON_TARGET, ICON_EYE, ICON_CLOCK, ICON_GIT_BRANCH,
13→  ICON_BAR_CHART_3, ICON_ZAP,
14→} from '@/lib/share-card-icons';
15→import { SOURCE_TOOL_DISPLAY_NAMES } from '@/lib/share-card-icons';
16→
17→const FONT_STACK = 'system-ui, -apple-system, "Segoe UI", Roboto, sans-serif';
18→const MONO_STACK = '"SF Mono", "Fira Code", "Cascadia Code", Consolas, monospace';
19→
20→// Physical resolution multiplier — draw at 2× for HiDPI PNG export
21→const DPR = 2;
22→
23→export interface ShareCardProps {
24→  tagline: string;
25→  dimensionScores: PQDimensionScores | null; // null = no PQ data
26→  totalSessions: number;       // sessions in 4-week scoring window
27→  totalTokens: number;         // tokens in 4-week scoring window
28→  lifetimeSessions: number;    // all-time session count
29→  sourceTools: string[];
30→  currentWeek: string;         // for month/year in header
31→  effectivePatterns?: Array<{ label: string; frequency: number }>; // top 3 by frequency
32→}
33→
34→/** Truncate text to fit within maxWidth, appending ellipsis if needed. */
35→function truncateText(ctx: CanvasRenderingContext2D, text: string, maxWidth: number): string {
36→  if (ctx.measureText(text).width <= maxWidth) return text;
37→  let truncated = text;
38→  while (truncated.length > 0 && ctx.measureText(truncated + '\u2026').width > maxWidth) {
39→    truncated = truncated.slice(0, -1);
40→  }
41→  return truncated + '\u2026';
42→}
43→
44→/**
45→ * Draw the favicon logo — indigo/purple gradient rounded rect with white magnifying
46→ * glass and amber crosshair. Matches dashboard/public/favicon.svg exactly.
47→ * (x, y) is top-left of the square; size is the side length in canvas pixels.
48→ */
49→function drawLogo(ctx: CanvasRenderingContext2D, x: number, y: number, size: number): void {
50→  const scale = size / 32; // favicon viewBox is 32×32
51→
52→  ctx.save();
53→  ctx.translate(x, y);
54→  ctx.scale(scale, scale);
55→
56→  // Background: indigo→purple gradient rounded rect (rx=7)
57→  const bgGrad = ctx.createLinearGradient(0, 0, 32, 32);
58→  bgGrad.addColorStop(0, '#6366f1');
59→  bgGrad.addColorStop(1, '#8b5cf6');
60→  ctx.fillStyle = bgGrad;
61→  ctx.beginPath();
62→  ctx.roundRect(0, 0, 32, 32, 7);
63→  ctx.fill();
64→
65→  // Magnifying glass: white circle at (18,14) r=6
66→  ctx.strokeStyle = 'white';
67→  ctx.lineWidth = 1.5;
68→  ctx.lineCap = 'round';
69→  ctx.beginPath();
70→  ctx.arc(18, 14, 6, 0, Math.PI * 2);
71→  ctx.stroke();
72→
73→  // Handle: white line from (22.2,18.2) to (25.5,21.5)
74→  ctx.beginPath();
75→  ctx.moveTo(22.2, 18.2);
76→  ctx.lineTo(25.5, 21.5);
77→  ctx.stroke();
78→
79→  // Amber crosshair center dot at (18,13) r=0.7
80→  const accentGrad = ctx.createLinearGradient(0, 0, 32, 32);

 1→// Canvas 2D icon rendering for share card.
