18→/**
19→ * Check if a port is already in use.
20→ * - Checks only EADDRINUSE, not other errors (e.g. EACCES for privileged ports).
21→ * - Waits for the test socket to fully close before resolving, avoiding a TOCTOU
22→ *   race where the real server tries to bind before the OS releases the port.
23→ */
24→function isPortInUse(port: number): Promise<boolean> {
25→  return new Promise((resolvePromise) => {
26→    const server = net.createServer();
27→    server.once('error', (err: NodeJS.ErrnoException) => {
28→      server.close();
29→      resolvePromise(err.code === 'EADDRINUSE');
30→    });
31→    server.once('listening', () => {
32→      // Wait for close callback before resolving so the OS fully releases the port
33→      server.close(() => resolvePromise(false));
34→    });
35→    server.listen(port, '127.0.0.1');
36→  });
37→}
