39→/**
40→ * Start the Code Insights local dashboard server.
41→ *
42→ * Loads server/dist/index.js by file URL rather than package name to avoid a
43→ * circular workspace dependency (server depends on @code-insights/cli, so CLI
44→ * cannot list @code-insights/server as a build-time dep). pathToFileURL ensures
45→ * the import works on Windows where absolute paths like C:\... are not valid
46→ * ESM import specifiers.
47→ */
48→export async function dashboardCommand(options: DashboardOptions): Promise<void> {
49→  // Auto-sync sessions before starting the dashboard so users see fresh data.
50→  // Skipped with --no-sync. Uses quiet:false so sync progress is visible on first run.
51→  if (options.sync !== false) {
52→    try {
53→      await runSync({ quiet: false });
54→      void identifyUser();
55→    } catch (err) {
56→      // Sync failure is non-fatal — dashboard still opens with whatever data exists
57→      console.warn(chalk.yellow(`  Sync warning: ${err instanceof Error ? err.message : String(err)}`));
58→      console.warn(chalk.dim('  Use --no-sync to skip sync, or run `code-insights sync` separately.'));
59→    }
60→  }

