105→/**
106→ * Derive month + year label from an ISO week string (e.g. "2026-W11" → "Mar 2026").
107→ */
108→function getMonthYearFromWeek(isoWeek: string): string {
109→  const match = /^(\d{4})-W(\d{2})$/.exec(isoWeek);
110→  if (!match) {
111→    return new Date().toLocaleDateString('en-US', { month: 'short', year: 'numeric' });
112→  }
113→  const year = parseInt(match[1], 10);
114→  const week = parseInt(match[2], 10);
115→  const jan4 = new Date(Date.UTC(year, 0, 4));
116→  const jan4Day = jan4.getUTCDay();
117→  const daysToMonday = jan4Day === 0 ? 6 : jan4Day - 1;
118→  const week1Monday = new Date(jan4.getTime() - daysToMonday * 86400000);
119→  const weekMonday = new Date(week1Monday.getTime() + (week - 1) * 7 * 86400000);
120→  return weekMonday.toLocaleDateString('en-US', { month: 'short', year: 'numeric', timeZone: 'UTC' });
121→}
