123→/** Format token count: 1,200,000 → "1.2M tokens", 850,000 → "850K tokens". */
124→function abbreviateTokens(n: number): string {
125→  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M tokens`;
126→  if (n >= 1_000) return `${Math.round(n / 1_000)}K tokens`;
127→  return `${n} tokens`;
128→}
