131→function scoreColors(score: number | null): { numberColor: string; arcStart: string; arcEnd: string } {
132→  if (score === null) return { numberColor: '#64748b', arcStart: '#64748b', arcEnd: '#475569' };
133→  if (score >= 80) return { numberColor: '#f1f5f9', arcStart: '#6366f1', arcEnd: '#d946ef' };
