239→  ctx.globalAlpha = 0.04;
240→  const WATERMARK_SIZE = 160;
241→  drawLogo(ctx, SCORE_CX - WATERMARK_SIZE / 2, SCORE_CY - WATERMARK_SIZE / 2, WATERMARK_SIZE);
242→  ctx.globalAlpha = 1.0;
243→
244→  // Track ring (full circle background)
245→  ctx.beginPath();
246→  ctx.arc(SCORE_CX, SCORE_CY, SCORE_R, 0, Math.PI * 2);
247→  ctx.strokeStyle = 'rgba(255,255,255,0.06)';
248→  ctx.lineWidth = 8;
249→  ctx.stroke();
250→
251→  // Score arc (filled portion) — save/restore to prevent lineCap leaking to subsequent strokes
252→  if (score !== null && score > 0) {
253→    ctx.save();
254→    const arcGradient = ctx.createLinearGradient(
255→      SCORE_CX - SCORE_R, SCORE_CY,
256→      SCORE_CX + SCORE_R, SCORE_CY
257→    );
258→    arcGradient.addColorStop(0, colors.arcStart);
259→    arcGradient.addColorStop(1, colors.arcEnd);
260→
261→    const startAngle = -Math.PI / 2; // 12 o'clock
262→    const endAngle = startAngle + (score / 100) * Math.PI * 2;
263→
264→    ctx.beginPath();
265→    ctx.arc(SCORE_CX, SCORE_CY, SCORE_R, startAngle, endAngle);
266→    ctx.strokeStyle = arcGradient;
267→    ctx.lineWidth = 8;
268→    ctx.lineCap = 'round';
269→    ctx.stroke();
270→    ctx.restore();
271→  }
272→
273→  // Score number
274→  ctx.textAlign = 'center';
275→  if (score !== null) {
276→    ctx.font = `700 72px ${FONT_STACK}`;
277→    ctx.fillStyle = colors.numberColor;
278→    ctx.fillText(String(score), SCORE_CX, 316);
279→  } else {
280→    ctx.font = `700 64px ${FONT_STACK}`;
281→    ctx.fillStyle = '#64748b';
282→    ctx.fillText('—', SCORE_CX, 316);
283→  }
284→
285→  ctx.font = `600 13px ${FONT_STACK}`;
286→  ctx.fillStyle = '#64748b';
287→  ctx.letterSpacing = '1.5px';
288→  ctx.fillText('AI FLUENCY', SCORE_CX, 354);
289→  ctx.letterSpacing = '0px';
290→
291→  ctx.font = `600 11px ${FONT_STACK}`;
292→  ctx.fillStyle = '#4a4a62';
293→  ctx.letterSpacing = '2px';
294→  ctx.fillText('SCORE', SCORE_CX, 372);
295→  ctx.letterSpacing = '0px';
296→
297→  ctx.textAlign = 'left';
298→
299→  // ── Section 4: Fingerprint Bars (right zone) ──────────────────────────────────
300→  //
301→  // Label zone: LABEL_LEFT_X → BAR_START_X - GAP
302→  // Labels (icon + text) are right-aligned to LABEL_RIGHT_X so all bars start
303→  // at exactly BAR_START_X regardless of label width.
304→
305→  const BAR_START_X = 560;
306→  const BAR_END_X = W - PAD; // 1152
307→  const BAR_MAX_W = BAR_END_X - BAR_START_X; // 592
308→  const BAR_H = 20;
309→  const BAR_RADIUS = 10;
310→  const ICON_SIZE = 16;
311→  const ICON_GAP = 8;
312→  const LABEL_RIGHT_X = BAR_START_X - 14; // all labels right-align here
313→  const MIN_FILL_W = 20;
314→
315→  for (const bar of FINGERPRINT_BARS) {
316→    const barY = bar.yCentre - BAR_H / 2;
317→    // Dimension score is null if no data for this dimension — show track only (no fill)
318→    const dimScore: number | null = props.dimensionScores
319→      ? (props.dimensionScores[bar.field as keyof PQDimensionScores] as number | null)
320→      : null;
321→
322→    // Draw bar track (full width pill)
323→    ctx.fillStyle = 'rgba(255,255,255,0.04)';
324→    ctx.beginPath();
325→    ctx.roundRect(BAR_START_X, barY, BAR_MAX_W, BAR_H, BAR_RADIUS);
326→    ctx.fill();
327→
328→    ctx.strokeStyle = 'rgba(255,255,255,0.06)';
329→    ctx.lineWidth = 1;
330→    ctx.beginPath();
331→    ctx.roundRect(BAR_START_X, barY, BAR_MAX_W, BAR_H, BAR_RADIUS);
332→    ctx.stroke();
333→
334→    // Draw bar fill — only if dimension has data. Null = no data, skip fill entirely.
335→    if (dimScore !== null) {
336→      const fillW = Math.max(MIN_FILL_W, Math.round((dimScore / 100) * BAR_MAX_W));
337→      ctx.fillStyle = bar.color;
338→      ctx.beginPath();
339→      ctx.roundRect(BAR_START_X, barY, fillW, BAR_H, BAR_RADIUS);
340→      ctx.fill();
341→    }
342→
343→    // Draw label: icon + text, right-aligned at LABEL_RIGHT_X
344→    // Measure first, then position so the right edge lands exactly at LABEL_RIGHT_X
345→    ctx.font = `500 12px ${FONT_STACK}`;
346→    const labelTextW = ctx.measureText(bar.label).width;
347→    const totalLabelW = ICON_SIZE + ICON_GAP + labelTextW;
348→    const iconX = LABEL_RIGHT_X - totalLabelW;
349→    const iconY = bar.yCentre - ICON_SIZE / 2;
350→
351→    drawIcon(ctx, bar.icon, iconX, iconY, ICON_SIZE, bar.color);
352→
353→    ctx.fillStyle = '#6b6b88';
354→    ctx.fillText(bar.label, iconX + ICON_SIZE + ICON_GAP, bar.yCentre + 4);
355→  }
356→
357→  // ── Section 5: Evidence Lines (y=420, y=452) ──────────────────────────────────
358→  // Line 1: scoring context — sample size + time window
359→  // Line 2: total sessions + tool logos with names
360→
361→  const EVIDENCE_CENTER_X = 600;
362→  const EVIDENCE_Y1 = 422;
363→  const EVIDENCE_Y2 = 458;
364→
365→  // Line 1: "Score from {N} sessions · {tokens} · last 4 weeks"
366→  if (props.totalSessions > 0 || props.dimensionScores) {
367→    const ICON_SMALL = 16;
368→    const prefix = 'Score from ';
369→    const sessionLabel = `${props.totalSessions} session${props.totalSessions !== 1 ? 's' : ''}`;
370→    const tokenLabel = abbreviateTokens(props.totalTokens);
371→    const windowLabel = 'last 4 weeks';
372→    const SEP = '  ·  ';
373→
374→    ctx.font = `500 17px ${FONT_STACK}`;
375→    const prefixW = ctx.measureText(prefix).width;
376→    const sessionW = ctx.measureText(sessionLabel).width;
377→    const tokenW = ctx.measureText(tokenLabel).width;
378→    const windowW = ctx.measureText(windowLabel).width;
379→    const sepW = ctx.measureText(SEP).width;
380→
381→    const line1TotalW = prefixW + sessionW + sepW + tokenW + sepW + windowW;
382→    let x1 = EVIDENCE_CENTER_X - line1TotalW / 2;
383→
384→    ctx.fillStyle = '#64748b';
385→    ctx.fillText(prefix, x1, EVIDENCE_Y1);
386→    x1 += prefixW;
387→
388→    ctx.fillStyle = '#94a3b8';
389→    ctx.fillText(sessionLabel, x1, EVIDENCE_Y1);
390→    x1 += sessionW;
391→
392→    ctx.fillStyle = '#3a3a52';
393→    ctx.fillText(SEP, x1, EVIDENCE_Y1);
394→    x1 += sepW;
395→
396→    ctx.fillStyle = '#94a3b8';
397→    ctx.fillText(tokenLabel, x1, EVIDENCE_Y1);
398→    x1 += tokenW;
399→
400→    ctx.fillStyle = '#3a3a52';
401→    ctx.fillText(SEP, x1, EVIDENCE_Y1);
402→    x1 += sepW;
403→
404→    ctx.fillStyle = '#64748b';
405→    ctx.fillText(windowLabel, x1, EVIDENCE_Y1);
406→  } else {
407→    ctx.font = `500 17px ${FONT_STACK}`;
408→    ctx.fillStyle = '#475569';
409→    ctx.textAlign = 'center';
410→    ctx.fillText('Get started at code-insights.app', EVIDENCE_CENTER_X, EVIDENCE_Y1);
411→    ctx.textAlign = 'left';
412→  }
413→
414→  // Line 2: {N} total sessions · [logo] Tool Name [logo] Tool Name ...
415→  {
416→    const lifetimeLabel = `${props.lifetimeSessions} total sessions`;
417→    const dedupedTools = deduplicateToolsForIcons(props.sourceTools).slice(0, 4);
418→    const LOGO_PX = 20;
419→    const LOGO_TEXT_GAP = 6;
420→    const LOGO_ENTRY_GAP = 16; // gap between tool entries
421→    const SEP = '  ·  ';
422→
423→    ctx.font = `400 15px ${FONT_STACK}`;
424→    const totalSessionsW = ctx.measureText(lifetimeLabel).width;
425→    const sepW2 = ctx.measureText(SEP).width;
426→
427→    // Pre-measure each tool entry width: logo + gap + label text
428→    const toolEntries = dedupedTools
429→      .filter(t => toolIcons.has(t))
430→      .map(t => {
431→        const label = SOURCE_TOOL_DISPLAY_NAMES[t] ?? t;
432→        const labelW = ctx.measureText(label).width;
433→        return { tool: t, label, entryW: LOGO_PX + LOGO_TEXT_GAP + labelW };
434→      });
435→
436→    const logosW = toolEntries.length > 0
437→      ? toolEntries.reduce((s, e) => s + e.entryW, 0) + (toolEntries.length - 1) * LOGO_ENTRY_GAP
438→      : 0;
439→
440→    const line2TotalW = totalSessionsW + (toolEntries.length > 0 ? sepW2 + logosW : 0);
441→    let x2 = EVIDENCE_CENTER_X - line2TotalW / 2;
442→
443→    ctx.fillStyle = '#64748b';
444→    ctx.fillText(lifetimeLabel, x2, EVIDENCE_Y2);
445→    x2 += totalSessionsW;
446→
447→    if (toolEntries.length > 0) {
448→      ctx.fillStyle = '#3a3a52';
449→      ctx.fillText(SEP, x2, EVIDENCE_Y2);
450→      x2 += sepW2;
451→
452→      for (let i = 0; i < toolEntries.length; i++) {
453→        const { tool, label, entryW } = toolEntries[i];
454→        const img = toolIcons.get(tool);
455→        if (img) {
456→          const cy = EVIDENCE_Y2 - LOGO_PX / 2 + 2;
457→          drawToolIcon(ctx, img, x2 + LOGO_PX / 2, cy, LOGO_PX);
458→        }
459→        x2 += LOGO_PX + LOGO_TEXT_GAP;
460→
461→        ctx.fillStyle = '#94a3b8';
462→        ctx.fillText(label, x2, EVIDENCE_Y2);
463→        x2 += entryW - LOGO_PX - LOGO_TEXT_GAP;
464→
465→        if (i < toolEntries.length - 1) x2 += LOGO_ENTRY_GAP;
466→      }
467→    }
468→  }
469→
470→  // ── Section 6: Effective Pattern Pills (y=494) ────────────────────────────────
471→
472→  const topPatterns = (props.effectivePatterns ?? []).slice(0, 3);
473→  if (topPatterns.length > 0) {
474→    const PILL_H = 28;
475→    const PILL_PAD_X = 12;
476→    const PILL_GAP = 10;
477→    const PILL_Y = 494;
478→
479→    ctx.font = `500 13px ${FONT_STACK}`;
480→    const STAR = '★ ';
481→    const starW = ctx.measureText(STAR).width;
482→
483→    // Measure all pills first to center them as a group
484→    const pillWidths = topPatterns.map(p => {
485→      const labelW = ctx.measureText(p.label).width;
486→      return PILL_PAD_X * 2 + starW + labelW;
487→    });
488→    const totalPillsW = pillWidths.reduce((s, w) => s + w, 0) + PILL_GAP * (topPatterns.length - 1);
489→    let pillX = EVIDENCE_CENTER_X - totalPillsW / 2;
490→
491→    for (let i = 0; i < topPatterns.length; i++) {
492→      const pattern = topPatterns[i];
493→      const pillW = pillWidths[i];
494→      const pc = PATTERN_PILL_COLORS[i % PATTERN_PILL_COLORS.length];
495→
496→      // Pill background
497→      ctx.fillStyle = pc.bg;
498→      ctx.beginPath();
499→      ctx.roundRect(pillX, PILL_Y, pillW, PILL_H, PILL_H / 2);
500→      ctx.fill();
501→
502→      // Pill border
503→      ctx.strokeStyle = pc.border;
504→      ctx.lineWidth = 1;
505→      ctx.beginPath();
506→      ctx.roundRect(pillX, PILL_Y, pillW, PILL_H, PILL_H / 2);
507→      ctx.stroke();
508→
509→      // Star + label text
510→      const textBaseline = PILL_Y + PILL_H * 0.65;
511→      ctx.fillStyle = pc.text;
512→      ctx.fillText(STAR, pillX + PILL_PAD_X, textBaseline);
513→      ctx.fillText(pattern.label, pillX + PILL_PAD_X + starW, textBaseline);
514→
515→      pillX += pillW + PILL_GAP;
516→    }
517→  }
518→
519→  // ── Section 7: Footer (pinned to bottom) ─────────────────────────────────────
520→
521→  const DIVIDER_Y = H - 90; // 540
522→  const FOOTER_Y = H - 54;  // 576
523→
524→  ctx.strokeStyle = 'rgba(255,255,255,0.06)';
525→  ctx.lineWidth = 1;
526→  ctx.beginPath();
527→  ctx.moveTo(PAD, DIVIDER_Y);
528→  ctx.lineTo(W - PAD, DIVIDER_Y);
529→  ctx.stroke();
530→
531→  const FOOTER_LOGO_SIZE = 22;
532→  drawLogo(ctx, PAD, FOOTER_Y - FOOTER_LOGO_SIZE + 4, FOOTER_LOGO_SIZE);
533→
534→  ctx.font = `400 15px ${FONT_STACK}`;
535→  ctx.fillStyle = '#475569';
536→  ctx.fillText('code-insights.app', PAD + FOOTER_LOGO_SIZE + 10, FOOTER_Y);
537→
538→  // CLI CTA: `npx @code-insights/cli` — monospace, terminal-style with subtle bg
539→  const CLI_CMD = 'npx @code-insights/cli';
540→  ctx.font = `500 13px ${MONO_STACK}`;
541→  const cmdW = ctx.measureText(CLI_CMD).width;
542→  const CMD_PAD_X = 10;
543→  const CMD_PAD_Y = 6;
544→  const CMD_H = 22;
545→  const cmdBoxW = cmdW + CMD_PAD_X * 2;
546→  const cmdBoxX = W - PAD - cmdBoxW;
547→  const cmdBoxY = FOOTER_Y - CMD_H + CMD_PAD_Y - 1;
548→
549→  // Terminal command background
550→  ctx.fillStyle = 'rgba(255,255,255,0.06)';
551→  ctx.beginPath();
552→  ctx.roundRect(cmdBoxX, cmdBoxY, cmdBoxW, CMD_H, 4);
553→  ctx.fill();
554→
555→  ctx.strokeStyle = 'rgba(255,255,255,0.12)';
556→  ctx.lineWidth = 1;
557→  ctx.beginPath();
558→  ctx.roundRect(cmdBoxX, cmdBoxY, cmdBoxW, CMD_H, 4);
559→  ctx.stroke();
