565→/**
566→ * Create an ephemeral 2× canvas, draw the share card at HiDPI resolution,
567→ * then export as a 1200×630 PNG (OG image standard for X, LinkedIn, Slack,
568→ * Discord). The draw canvas is 2400×1260 (2× of 1200×630 logical coords)
569→ * for crisp text on Retina/HiDPI displays.
570→ */
571→export async function downloadShareCard(props: ShareCardProps): Promise<void> {
572→  // Pre-load tool logos before drawing (canvas drawImage requires loaded images)
573→  const toolIcons = await loadToolIcons(props.sourceTools);
574→
575→  // Internal draw canvas: 1200×630 logical, 2400×1260 physical (DPR=2)
576→  const LOGICAL_W = 1200;
577→  const LOGICAL_H = 630;
578→
579→  const drawCanvas = document.createElement('canvas');
580→  drawCanvas.width = LOGICAL_W * DPR;   // 2400
581→  drawCanvas.height = LOGICAL_H * DPR;  // 1260
582→  drawShareCard(drawCanvas, props, toolIcons);
583→
584→  // Export at 1200×630 (OG standard) — scale from 2400×1260 internal (clean 2× downscale)
585→  const exportCanvas = document.createElement('canvas');
586→  exportCanvas.width = LOGICAL_W;
587→  exportCanvas.height = LOGICAL_H;
588→  const exportCtx = exportCanvas.getContext('2d');
589→  if (!exportCtx) throw new Error('Failed to get 2D context for export canvas');
590→
591→  exportCtx.drawImage(drawCanvas, 0, 0, LOGICAL_W, LOGICAL_H);
592→
593→  const blob = await new Promise<Blob>((resolve, reject) =>
594→    exportCanvas.toBlob((b) => {
595→      if (b) resolve(b);
596→      else reject(new Error('canvas.toBlob returned null'));
597→    }, 'image/png')
598→  );
599→
600→  const url = URL.createObjectURL(blob);
601→  const link = document.createElement('a');
602→  link.download = 'code-insights-ai-fluency.png';
603→  link.href = url;
604→  link.click();
605→  URL.revokeObjectURL(url);
606→}
