 93→/**
 94→ * Draw a Lucide-style icon on canvas at (x, y) with given size and color.
 95→ * Icons are defined in 24×24 viewBox coordinates and scaled to `size` pixels.
 96→ * Uses ctx.save()/restore() to sandbox transform state.
 97→ */
 98→export function drawIcon(
 99→  ctx: CanvasRenderingContext2D,
100→  icon: IconDef,
101→  x: number,
102→  y: number,
103→  size: number,
104→  color: string
105→): void {
106→  const scale = size / 24;
107→
108→  ctx.save();
109→  ctx.translate(x, y);
110→  ctx.scale(scale, scale);
111→
112→  ctx.strokeStyle = color;
113→  ctx.lineWidth = 2 / scale; // keep 2px stroke weight regardless of scale
114→  ctx.lineCap = 'round';
115→  ctx.lineJoin = 'round';
116→
117→  // Paths
118→  for (const d of icon.paths) {
119→    const path = new Path2D(d);
120→    ctx.stroke(path);
121→  }
122→
123→  // Circles (no fill — stroke only to match Lucide outline style)
124→  for (const c of icon.circles ?? []) {
125→    ctx.beginPath();
126→    ctx.arc(c.cx, c.cy, c.r, 0, Math.PI * 2);
127→    ctx.stroke();
128→  }
129→
130→  // Lines
131→  for (const l of icon.lines ?? []) {
132→    ctx.beginPath();
133→    ctx.moveTo(l.x1, l.y1);
134→    ctx.lineTo(l.x2, l.y2);
135→    ctx.stroke();
136→  }
137→
138→  // Polylines (space-separated x y pairs)
139→  for (const pts of icon.polylines ?? []) {
140→    const nums = pts.trim().split(/\s+/).map(Number);
141→    ctx.beginPath();
142→    for (let i = 0; i < nums.length; i += 2) {
143→      if (i === 0) ctx.moveTo(nums[0], nums[1]);
144→      else ctx.lineTo(nums[i], nums[i + 1]);
145→    }
146→    ctx.stroke();
147→  }
148→
149→  ctx.restore();
150→}
