154→/**
155→ * Deduplication: copilot + copilot-cli map to the same icon.
156→ * Returns a deduplicated list of unique tool identifiers for icon rendering.
157→ */
158→export function deduplicateToolsForIcons(sourceTools: string[]): string[] {
159→  const seen = new Set<string>();
160→  const result: string[] = [];
161→  for (const tool of sourceTools) {
162→    // Both copilot variants share the same icon — normalize to 'copilot'
163→    const key = tool === 'copilot-cli' ? 'copilot' : tool;
164→    if (!seen.has(key)) {
165→      seen.add(key);
166→      result.push(key);
167→    }
168→  }
169→  return result;
170→}
