189→/** Pre-load tool logo images. Returns a map of tool key → HTMLImageElement. */
190→export async function loadToolIcons(tools: string[]): Promise<Map<string, HTMLImageElement>> {
191→  const deduped = deduplicateToolsForIcons(tools);
192→  const entries = await Promise.all(
193→    deduped.map(async (tool) => {
194→      const url = TOOL_ICON_URLS[tool];
195→      if (!url) return null;
196→      const img = new Image();
197→      await new Promise<void>((resolve) => {
198→        img.onload = () => resolve();
199→        img.onerror = () => resolve(); // skip broken icons gracefully
200→        img.src = url;
201→      });
202→      return [tool, img] as const;
203→    })
204→  );
205→  return new Map(entries.filter((e): e is [string, HTMLImageElement] => e !== null && e[1].complete && e[1].naturalWidth > 0));
206→}
