208→/**
209→ * Draw a tool logo at (cx, cy) as an 18×18 circle-clipped image.
210→ * cx/cy are the CENTER of the circle.
211→ */
212→export function drawToolIcon(
213→  ctx: CanvasRenderingContext2D,
214→  img: HTMLImageElement,
215→  cx: number,
216→  cy: number,
217→  size: number = 18
218→): void {
219→  const r = size / 2;
220→  ctx.save();
221→  ctx.beginPath();
222→  ctx.arc(cx, cy, r, 0, Math.PI * 2);
223→  ctx.clip();
224→  ctx.drawImage(img, cx - r, cy - r, size, size);
225→  ctx.restore();
226→}
