 10→// ISO week regex: matches YYYY-WNN format (e.g., 2026-W10)
 11→const ISO_WEEK_RE = /^(\d{4})-W(\d{2})$/;
 12→
 13→/**
 14→ * Parse an ISO week string (YYYY-WNN) into UTC Monday/Sunday boundaries.
 15→ * Returns { start: Monday 00:00 UTC, end: next Monday 00:00 UTC } (exclusive end).
 16→ *
 17→ * ISO 8601 week rules: week 1 contains the first Thursday of the year,
 18→ * weeks start on Monday. We use the "Thursday trick": Jan 4 is always
 19→ * in week 1, so we find that Monday, then step to the target week.
 20→ */
 21→export function parseIsoWeek(weekStr: string): { start: Date; end: Date } | null {
 22→  const match = ISO_WEEK_RE.exec(weekStr);
 23→  if (!match) return null;
 24→
 25→  const year = parseInt(match[1], 10);
 26→  const week = parseInt(match[2], 10);
 27→  if (week < 1 || week > 53) return null;
 28→
 29→  // Jan 4 is always in ISO week 1. Find that Monday.
 30→  const jan4 = new Date(Date.UTC(year, 0, 4));
 31→  const jan4Day = jan4.getUTCDay(); // 0=Sun, 1=Mon, ..., 6=Sat
 32→  // Days to Monday of week 1: if Sunday (0), go back 6; else go back (day - 1)
 33→  const daysToMonday = jan4Day === 0 ? 6 : jan4Day - 1;
 34→  const week1Monday = new Date(jan4.getTime() - daysToMonday * 86400000);
 35→
 36→  // Offset to the target week's Monday
 37→  const start = new Date(week1Monday.getTime() + (week - 1) * 7 * 86400000);
 38→  const end = new Date(start.getTime() + 7 * 86400000);
 39→
 40→  return { start, end };
 41→}
 42→
 43→/**
 44→ * Format a Date (representing a Monday) as an ISO week string (YYYY-WNN).
 45→ * Used when generating week inventory from a list of Mondays.
 46→ */
 47→export function formatIsoWeek(monday: Date): string {
 48→  // Find which ISO week number this Monday belongs to.
 49→  // The Monday's Thursday (3 days ahead) determines the year and week.
 50→  const thursday = new Date(monday.getTime() + 3 * 86400000);
 51→  const year = thursday.getUTCFullYear();
 52→
 53→  // Find the Monday of week 1 for this ISO year
 54→  const jan4 = new Date(Date.UTC(year, 0, 4));
 55→  const jan4Day = jan4.getUTCDay();
 56→  const daysToMonday = jan4Day === 0 ? 6 : jan4Day - 1;
 57→  const week1Monday = new Date(jan4.getTime() - daysToMonday * 86400000);
 58→
 59→  const weekNum = Math.round((monday.getTime() - week1Monday.getTime()) / (7 * 86400000)) + 1;
 60→  return `${year}-W${String(weekNum).padStart(2, '0')}`;
 61→}
 62→
 63→export function buildPeriodFilter(period: string): string | null {
 64→  const now = new Date();
 65→  if (period === '7d') return new Date(now.getTime() - 7 * 86400000).toISOString();
 66→  if (period === '30d') return new Date(now.getTime() - 30 * 86400000).toISOString();
 67→  if (period === '90d') return new Date(now.getTime() - 90 * 86400000).toISOString();
 68→  return null; // 'all'
 69→}
 70→
 71→export function buildWhereClause(
 72→  period: string,
 73→  project?: string,
 74→  source?: string
 75→): { where: string; params: (string | number)[] } {
 76→  // Always exclude soft-deleted sessions from aggregations
 77→  const conditions: string[] = ['s.deleted_at IS NULL'];
 78→  const params: (string | number)[] = [];
 79→
 80→  // ISO week period: use precise Monday-to-Monday UTC boundaries
 81→  const isoWeekBounds = parseIsoWeek(period);
 82→  if (isoWeekBounds) {
 83→    conditions.push('s.started_at >= ?');
 84→    params.push(isoWeekBounds.start.toISOString());
 85→    conditions.push('s.started_at < ?');
 86→    params.push(isoWeekBounds.end.toISOString());
 87→  } else {
 88→    const periodStart = buildPeriodFilter(period);
 89→    if (periodStart) {
 90→      conditions.push('s.started_at >= ?');
 91→      params.push(periodStart);
 92→    }
 93→  }
 94→
 95→  if (project) {
 96→    conditions.push('s.project_id = ?');
 97→    params.push(project);
 98→  }
 99→  if (source) {
100→    conditions.push('s.source_tool = ?');
101→    params.push(source);
102→  }
103→
104→  return {
105→    where: `WHERE ${conditions.join(' AND ')}`,
106→    params,
107→  };
108→}
