170→ *
171→ * project and source are passed separately so streak can build its own
172→ * period-free where clause (streak measures continuity across all time).
173→ */
174→export function getAggregatedData(
175→  db: ReturnType<typeof getDb>,
176→  where: string,
177→  params: (string | number)[],
178→  project?: string,
179→  source?: string
180→): AggregatedData {
181→  const hasWhere = where.length > 0;
182→  const extraPrefix = hasWhere ? 'AND' : 'WHERE';
183→
184→  const frictionCategories = db.prepare(`
185→    SELECT
186→      json_extract(je.value, '$.category') as category,
187→      COUNT(*) as count,
188→      AVG(CASE
189→        WHEN json_extract(je.value, '$.severity') = 'high' THEN 3
190→        WHEN json_extract(je.value, '$.severity') = 'medium' THEN 2
191→        ELSE 1
192→      END) as avg_severity,
193→      json_group_array(json_extract(je.value, '$.description')) as examples,
194→      json_group_array(sf.session_id) as session_ids
195→    FROM session_facets sf
196→    JOIN sessions s ON sf.session_id = s.id
197→    CROSS JOIN json_each(sf.friction_points) je
198→    ${where}
199→    GROUP BY category
200→    ORDER BY count DESC, avg_severity DESC
201→  `).all(...params) as Array<{ category: string; count: number; avg_severity: number; examples: string; session_ids: string }>;
202→
203→  // Fetch effective patterns with confidence >= 50.
204→  // Category-based grouping happens in code (post-query) after normalizePatternCategory()
205→  // to handle any LLM variants that were stored before normalization was applied at write time.
206→  // extraPrefix handles the case where where is '' (tests pass empty string) vs a WHERE clause.
207→  const effectivePatternsRaw = db.prepare(`
208→    SELECT
209→      json_extract(je.value, '$.category') as category,
210→      json_extract(je.value, '$.description') as description,
211→      json_extract(je.value, '$.confidence') as confidence,
212→      json_extract(je.value, '$.driver') as driver
213→    FROM session_facets sf
214→    JOIN sessions s ON sf.session_id = s.id
215→    CROSS JOIN json_each(sf.effective_patterns) je
216→    ${where}
217→    ${extraPrefix} json_extract(je.value, '$.confidence') >= 50
218→    ORDER BY json_extract(je.value, '$.confidence') DESC
219→  `).all(...params) as Array<{ category: string | null; description: string | null; confidence: number | null; driver: string | null }>;
220→
221→  const outcomeDistribution = db.prepare(`
222→    SELECT outcome_satisfaction, COUNT(*) as count
223→    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
224→    ${where}
225→    GROUP BY outcome_satisfaction
226→  `).all(...params) as Array<{ outcome_satisfaction: string; count: number }>;
227→
228→  const workflowDistribution = db.prepare(`
229→    SELECT workflow_pattern, COUNT(*) as count
230→    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
231→    ${where}
232→    ${extraPrefix} sf.workflow_pattern IS NOT NULL
233→    GROUP BY workflow_pattern
234→  `).all(...params) as Array<{ workflow_pattern: string; count: number }>;
235→
236→  const characterDistribution = db.prepare(`
237→    SELECT session_character, COUNT(*) as count
238→    FROM sessions s
239→    ${where}
240→    ${extraPrefix} s.session_character IS NOT NULL
241→    GROUP BY session_character
242→  `).all(...params) as Array<{ session_character: string; count: number }>;
243→
244→  const totalRow = db.prepare(
245→    `SELECT COUNT(*) as count FROM session_facets sf JOIN sessions s ON sf.session_id = s.id ${where}`
246→  ).get(...params) as { count: number };
247→
248→  const totalAllRow = db.prepare(
249→    `SELECT COUNT(*) as count FROM sessions s ${where}`
250→  ).get(...params) as { count: number };
251→
252→  // Parse examples and session_ids from json_group_array output, then normalize via alias + Levenshtein clustering
253→  const parsedFriction = frictionCategories.map(fc => ({
254→    ...fc,
255→    examples: JSON.parse(fc.examples) as string[],
256→    session_ids: JSON.parse(fc.session_ids) as string[],
257→  }));
258→
259→  const normalizedFriction = new Map<string, { count: number; total_severity: number; examples: string[]; session_ids: string[] }>();
260→  for (const fc of parsedFriction) {
261→    const normalized = normalizeFrictionCategory(fc.category);
262→    const existing = normalizedFriction.get(normalized);
263→    if (existing) {
264→      existing.count += fc.count;
265→      existing.total_severity += fc.avg_severity * fc.count;
266→      existing.examples.push(...fc.examples);
267→      existing.session_ids.push(...fc.session_ids);
268→    } else {
269→      normalizedFriction.set(normalized, {
270→        count: fc.count,
271→        total_severity: fc.avg_severity * fc.count,
272→        examples: [...fc.examples],
273→        session_ids: [...fc.session_ids],
274→      });
275→    }
276→  }
277→
278→  // Partition: separate rate-limit-hit entries from general friction.
279→  // Rate limits are a billing/plan constraint — surfaced as a usage insight, not friction.
280→  // The alias map already normalizes all rate limit variants to "rate-limit-hit".
281→  // A regex sweep catches creative LLM variants ("throttled-by-api", etc.) that bypass
282→  // both the alias map and Levenshtein clustering.
283→  const RATE_LIMIT_CATEGORY = 'rate-limit-hit';
284→  const RATE_LIMIT_REGEX = /rate.?limit|throttl/i;
285→  let rateLimitInfo: RateLimitInfo | null = null;
286→
287→  // Accumulated data for rateLimitInfo, merged from exact match + regex sweep
288→  let rateLimitCount = 0;
289→  let rateLimitSessionIds: string[] = [];
290→  let rateLimitExamples: string[] = [];
291→
292→  const rateLimitEntry = normalizedFriction.get(RATE_LIMIT_CATEGORY);
293→  if (rateLimitEntry) {
294→    rateLimitCount += rateLimitEntry.count;
295→    rateLimitSessionIds.push(...rateLimitEntry.session_ids);
296→    rateLimitExamples.push(...rateLimitEntry.examples);
297→    normalizedFriction.delete(RATE_LIMIT_CATEGORY);
298→  }
299→

